<span class="line"><span style="color:#CDD6F4;">            stdout</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">read_to_end</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CBA6F7;">mut</span><span style="color:#CDD6F4;"> buf</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">map</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;">_</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> buf</span><span style="color:#9399B2;">)</span></span>
